// Tech Stack Analysis for the incoming project
const { projectId, stageKey, executionId, subStage } = $input.first().json.body;

const techStackResult = {
  approaches: [
    {
      name: "Node.js + React + PostgreSQL",
      score: 88,
      strengths: ["Unified language (JS/TS)", "Large ecosystem", "Strong hiring pool", "Proven at scale"],
      weaknesses: ["CPU-bound task performance", "ORM complexity at scale"],
      cost: "Low — all OSS, cloud-native friendly",
      timeToMvp: "8-12 weeks"
    },
    {
      name: "Go + React + PostgreSQL",
      score: 82,
      strengths: ["Excellent concurrency", "Low resource footprint", "Strong typing", "Fast builds"],
      weaknesses: ["Smaller ecosystem for web", "Steeper learning curve", "Less frontend tooling integration"],
      cost: "Low — all OSS",
      timeToMvp: "10-14 weeks"
    },
    {
      name: "Python (FastAPI) + React + PostgreSQL",
      score: 79,
      strengths: ["AI/ML ecosystem", "Rapid prototyping", "Good for data pipelines"],
      weaknesses: ["GIL limits concurrency", "Type safety is opt-in", "Deployment complexity"],
      cost: "Low — all OSS",
      timeToMvp: "8-10 weeks"
    }
  ],
  tradeoffs: {
    performance: "Go leads for raw throughput; Node.js adequate for most web workloads; Python trails for concurrent connections",
    developerExperience: "Node.js/React provides best full-stack DX with shared tooling; Go requires context-switching; Python has excellent prototyping speed",
    scalability: "All three scale horizontally. Go has lowest per-instance cost. Node.js cluster mode is well-understood. Python needs more instances for equivalent throughput.",
    ecosystem: "Node.js has the broadest web ecosystem. Python leads for AI/data. Go is strong for infrastructure but thinner for web.",
    hiring: "Node.js/React developers are most available. Python developers are abundant but often specialized in data/ML. Go developers are fewer but typically senior."
  },
  recommendation: {
    choice: "Node.js + React + PostgreSQL",
    confidence: 0.85,
    summary: "Best balance of DX, ecosystem breadth, hiring pool, and time-to-MVP. The unified JS/TS stack reduces context-switching and enables code sharing between server and client. PostgreSQL provides the relational foundation with JSONB flexibility for semi-structured data.",
    keyDecisions: [
      "TypeScript everywhere for type safety",
      "PostgreSQL over MongoDB for relational integrity + JSONB flexibility",
      "React over Vue/Svelte for ecosystem and hiring",
      "Express or Fastify for API layer — low lock-in"
    ]
  }
};

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'tech_stack',
    techStackResult
  }
};
